using UnityEngine;

public class Player : MonoBehaviour
{
    public int health = 100;
    public int currency = 500;

    private const int maxHealth = 100;
    private const int minHealth = 0;
    private const int minCurrency = 0;

    void Start()
    {
        // Initialize player stats securely
        health = Mathf.Clamp(health, minHealth, maxHealth);
        currency = Mathf.Max(currency, minCurrency);
    }

    public void TakeDamage(int damage)
    {
        if (damage < 0) return; // Validate input
        health -= damage;
        health = Mathf.Clamp(health, minHealth, maxHealth);
    }

    public bool PurchaseItem(int price)
    {
        if (price < 0 || price > currency) return false; // Validate input
        currency -= price;
        return true;
    }
}

public class Shop : MonoBehaviour
{
    private Player player;

    void Start()
    {
        player = FindObjectOfType<Player>();
    }

    public void BuyHealthPotion()
    {
        int potionPrice = 100;
        if (player.PurchaseItem(potionPrice))
        {
            player.health = Mathf.Min(player.health + 20, Player.maxHealth);
        }
    }
}

public class SecureInputHandler : MonoBehaviour
{
    public static int ValidateAndParseInput(string input)
    {
        int result;
        if (int.TryParse(input, out result))
        {
            return Mathf.Max(result, 0); // Ensure non-negative
        }
        return 0;
    }
}